// --- Extract TRAIL_DATA JSON from an HTML file ---
function extractTrailData(htmlPath) {
  const html = fs.readFileSync(htmlPath, 'utf8');
  const marker = 'window.TRAIL_DATA = ';
  const start = html.indexOf(marker);
  if (start === -1) return null;

  // Find matching closing brace by tracking depth and strings
  let i = start + marker.length;
  let depth = 0;
  let inString = false;
  let escape = false;

  for (; i < html.length; i++) {
    const ch = html[i];
    if (escape) { escape = false; continue; }
    if (ch === '\\' && inString) { escape = true; continue; }
    if (ch === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (ch === '{') depth++;
    if (ch === '}') { depth--; if (depth === 0) break; }
  }

  const jsonStr = html.slice(start + marker.length, i + 1);
  return JSON.parse(jsonStr);
}

