  } else {
    console.log('Source: built-in (no source tracking)');
  }

  console.log(`${game.totalEvents} events (${game.quizCount} quiz + ${game.fortuneCount} fortune)`);
  console.log(`Party: ${game.partyMembers.join(', ')}`);
  console.log('');

  for (const event of game.events) {
