for (const q of expanded) {
  if (q.type === 'vec' || q.type === 'hyde')
    vecQueries.push({ text: q.query, queryType: q.type });
}
const embeddings = await llm.embedBatch(
  vecQueries.map(q => formatQueryForEmbedding(q.text))
);","language":"typescript"},"narration":"At Independence Rock, the trail splits into parallel paths. Lex expansions go straight to FTS5 keyword search since it is synchronous and instant. Vec and hyde expansions get batch-embedded in one call, then each runs a sqlite-vec lookup. The original query always runs both paths. Type routing avoids wasted work."},{"name":"South Pass","subtitle":"Reciprocal Rank Fusion","concept":"Position-Aware Blending","landmarkType":"river","code":{"file":"src/store.ts","content":"// src/store.ts — Reciprocal Rank Fusion (excerpt)
export function reciprocalRankFusion(
  resultLists: RankedResult[][],
  weights: number[] = [],
  k: number = 60
): RankedResult[] {
  const scores = new Map<string, {
    result: RankedResult; rrfScore: number;
    topRank: number }>;

  for (let listIdx = 0; listIdx < resultLists.length; listIdx++) {
    const weight = weights[listIdx] ?? 1.0;
    for (let rank = 0; rank < list.length; rank++) {
      const rrfContribution = weight / (k + rank + 1);
      // Accumulate per-document scores
      existing.rrfScore += rrfContribution;
    }
  }

  // Top-rank bonus
  for (const entry of scores.values()) {
    if (entry.topRank === 0) entry.rrfScore += 0.05;
    else if (entry.topRank <= 2) entry.rrfScore += 0.02;
  }
  return Array.from(scores.values())
    .sort((a, b) => b.rrfScore - a.rrfScore)
    .map(e => ({ ...e.result, score: e.rrfScore }));
}","language":"typescript"},"narration":"South Pass is where all the ranked lists converge into one river. Reciprocal Rank Fusion scores each document as weight divided by K plus rank plus 1. The first two lists, original FTS and original vector, get 2x weight because the user's exact words matter most. A top-rank bonus rewards documents that appeared at rank 1 across any list."},{"name":"Fort Bridger","subtitle":"LLM Re-ranking","concept":"Hybrid Search","landmarkType":"forest","code":{"file":"src/llm.ts","content":"// src/llm.ts — Reranking via createRankingContext (excerpt)
const DEFAULT_RERANK_MODEL =
  "hf:ggml-org/Qwen3-Reranker-0.6B-Q8_0-GGUF/"
  + "qwen3-reranker-0.6b-q8_0.gguf";

private async ensureRerankContexts() {
  const model = await this.ensureRerankModel();
  const n = Math.min(
    await this.computeParallelism(1000), 4);
  for (let i = 0; i < n; i++) {
    this.rerankContexts.push(
      await model.createRankingContext({
        contextSize: 2048, flashAttention: true,
      }));
  }
}

async rerank(query, documents, options) {
  const contexts = await this.ensureRerankContexts();
  // Split docs across contexts for parallel eval
  const chunks = splitIntoChunks(texts, contexts.length);
  const allScores = await Promise.all(
    chunks.map((chunk, i) =>
      contexts[i].rankAll(query, chunk))
  );
  return texts.map((t, i) =>
    ({ document: t, score: allScores.flat()[i] }))
    .sort((a, b) => b.score - a.score);
}","language":"typescript"},"narration":"Deep in the forest at Fort Bridger, the Qwen3 Reranker 0.6B acts as a wise judge. It uses createRankingContext and rankAll from node-llama-cpp to score each candidate chunk against the query. Up to 4 contexts run in parallel for throughput. The candidate limit is 40, not 30, keeping ranks 31 through 40 visible to catch broad queries."},{"name":"The Dalles","subtitle":"Position-Aware Blending","concept":"Position-Aware Blending","landmarkType":"camp","code":{"file":"src/store.ts","content":"// src/store.ts — Position-aware blending (excerpt)
export const RERANK_CANDIDATE_LIMIT = 40;

// Step 7: Blend RRF position score with reranker score
const blended = reranked.map(r => {
  const rrfRank = rrfRankMap.get(r.file) || candidateLimit;
  let rrfWeight: number;
  // Top tier: ranks 1-3 — trust retrieval most
  if (rrfRank <= 3) rrfWeight = 0.75;
  // Mid tier: ranks 4-10 — balanced
  else if (rrfRank <= 10) rrfWeight = 0.60;
  // Tail tier: ranks 11+ — trust reranker more
  else rrfWeight = 0.40;

  const rrfScore = 1 / rrfRank;
  const blendedScore =
    rrfWeight * rrfScore
    + (1 - rrfWeight) * r.score;

  return {
    file: r.file,
    score: blendedScore,
    tier: rrfRank <= 3 ? 'top'
      : rrfRank <= 10 ? 'mid' : 'tail'
  };
}).sort((a, b) => b.score - a.score);","language":"typescript"},"narration":"At The Dalles, we blend retrieval and reranker scores with position awareness. Top 3 results get 75 percent retrieval weight because BM25 and vector hits at the top are usually precise. Mid-tier ranks 4 through 10 are 60/40. Tail ranks 11 and beyond flip to 40/60, trusting the reranker to separate borderline relevant from irrelevant."},{"name":"Oregon City","subtitle":"Result Formatting","concept":"Smart Chunking","landmarkType":"town","code":{"file":"src/cli/formatter.ts","content":"// src/cli/formatter.ts — Output formatting (excerpt)
export type OutputFormat =
  "cli" | "csv" | "md" | "xml" | "files" | "json";

export function formatSearchResults(
  results: SearchResult[],
  format: OutputFormat,
  opts: FormatOptions = {}
): string {
  switch (format) {
    case "json":
      return searchResultsToJson(results, opts);
    case "csv":
      return searchResultsToCsv(results, opts);
    case "files":
      return searchResultsToFiles(results);
    case "md":
      return searchResultsToMarkdown(results, opts);
    case "xml":
      return searchResultsToXml(results, opts);
    default:
      return searchResultsToJson(results, opts);
  }
}

export function searchResultsToJson(
  results: SearchResult[], opts = {}
): string {
  return JSON.stringify(results.map(row => ({
    docid: `#${row.docid}`,
    score: Math.round(row.score * 100) / 100,
    file: row.displayPath,
    title: row.title,
  })), null, 2);
}","language":"typescript"},"narration":"You made it to Oregon City! The final stop formats results for humans or machines. Six output formats: CLI with colors, JSON for AI agents, CSV, Markdown, XML, and a simple files list. Each result carries a docid, score, file path, and title. The journey from raw query to ranked results is complete."}],"events":[{"type":"weather","trigger":"after_stop","triggerStop":1,"title":"A Search Storm Is Brewing!","text":"Dark clouds gather over the trail. Lightning illuminates three possible paths through the storm. What happens when you run `qmd query "deploy"`?","choices":[{"text":"Full hybrid pipeline with expansion, parallel search, fusion, reranking, and blending","correct":true,"explanation":"The `query` command activates the complete hybrid pipeline: LLM expansion generates typed variants, BM25 and vector search run in parallel, RRF fuses the ranked lists, the reranker judges candidates, and position-aware blending produces the final ranking."},{"text":"Just BM25 keyword search against the FTS5 index","correct":false,"explanation":"That would be the `search` command. The `query` command goes further with expansion, vector search, fusion, reranking, and blending."},{"text":"Just vector semantic search using embeddings","correct":false,"explanation":"That would be the `vsearch` command. The `query` command combines both keyword and semantic search with additional intelligence layers."}],"concept":"Hybrid Search","difficulty":"easy"},{"type":"encounter","trigger":"after_stop","triggerStop":2,"title":"A Fellow Traveler Shares Wisdom!","text":"A seasoned search engineer approaches your wagon. 'I see you check for strong BM25 signals before calling the LLM,' they say. 'Smart move.' Why check for strong BM25 signals before LLM expansion?","choices":[{"text":"Skip expensive LLM calls when an excellent exact match is already found","correct":true,"explanation":"If BM25 already finds a strong match above 0.85 with a gap of 0.15 to the runner-up, there is no need to spend time and compute on LLM query expansion. It is an optimization that avoids unnecessary work."},{"text":"BM25 is always more accurate than any other search method","correct":false,"explanation":"BM25 is great for exact keyword matches but misses conceptually similar documents with different vocabulary. The strong signal check is about efficiency, not superiority."},{"text":"LLMs are unreliable and should be avoided whenever possible","correct":false,"explanation":"LLMs are quite useful for query expansion and reranking. The strong signal check is an optimization, not a judgment on LLM quality."}],"concept":"Smart Chunking","difficulty":"easy"},{"type":"river","trigger":"after_stop","triggerStop":4,"title":"The Search River Crossing!","text":"You have reached a wide river where two search currents merge. On one bank, keywords. On the other, embeddings. How does semantic search differ from keyword search?","choices":[{"text":"Finds conceptually similar documents even when they use completely different words","correct":true,"explanation":"Vector semantic search converts text to embeddings that capture meaning. A search for 'deploy' can find documents about 'release pipeline' or 'shipping code' because the vectors are close in embedding space."},{"text":"It is faster because embeddings are precomputed","correct":false,"explanation":"Speed is not the key difference. Semantic search is about finding meaning-based similarity, not just matching the exact words in the query."},{"text":"It uses regular expressions to find pattern matches","correct":false,"explanation":"Regex is a completely different approach. Semantic search uses neural network embeddings to capture the meaning of text, not pattern matching."}],"concept":"Hybrid Search","difficulty":"medium"},{"type":"weather","trigger":"after_stop","triggerStop":5,"title":"Fusion Storm!","text":"A violent storm of ranked lists crashes together at South Pass. BM25 results, vector results, and expanded query results all compete for position. Why weight the original query 2x in RRF?","choices":[{"text":"The user's exact words should have more influence than LLM-generated expansions","correct":true,"explanation":"The original query directly reflects the user's intent. Expanded variants are helpful for coverage but the user's own words deserve more weight. Double weighting ensures the original query's top hits stay prominent."},{"text":"It is a random implementation choice with no particular reasoning","correct":false,"explanation":"The 2x weight is deliberate. The user typed those exact words for a reason. Expansion variants help find more results but should not override the user's stated intent."},{"text":"Expanded queries are inherently less accurate than the original","correct":false,"explanation":"Expansions are not less accurate — they find different relevant documents. The 2x weight is about respecting user intent, not about accuracy of expansions."}],"concept":"Position-Aware Blending","difficulty":"medium"},{"type":"misfortune","trigger":"after_stop","triggerStop":6,"title":"Reranker Breakdown!","text":"Disaster strikes! The reranker has gone haywire, promoting strange documents to the top of your results. What could go wrong if you ONLY used the reranker for final ranking?","choices":[{"text":"It might demote exact keyword matches the user specifically searched for","correct":true,"explanation":"A cross-encoder reranker optimizes for semantic relevance but can miss the importance of exact keyword matches. If someone searches for a specific function name, the reranker might rank a conceptually similar but different function higher."},{"text":"It would be too slow to return any results at all","correct":false,"explanation":"The reranker is slower than BM25 but still returns results. The real issue is ranking quality for exact matches, not speed."},{"text":"Rerankers cannot process text longer than 100 characters","correct":false,"explanation":"Modern rerankers handle substantial text. The issue is about ranking priorities, not input limitations."}],"concept":"Position-Aware Blending","difficulty":"medium"},{"type":"encounter","trigger":"after_stop","triggerStop":7,"title":"Position-Aware Pioneer!","text":"A pioneer who has traveled this trail before shares their hard-won knowledge. 'Trust retrieval for the top ranks,' they say. Why trust retrieval more for top-ranked results?","choices":[{"text":"Top BM25 and vector hits are usually precise; the reranker adds value for borderline results lower in the list","correct":true,"explanation":"When BM25 or vector search puts something at rank 1, it is almost certainly relevant. The reranker shines at positions 11 and beyond where it can distinguish truly relevant borderline results from noise. That is why ranks 1-3 get 75% retrieval weight."},{"text":"The reranker is always wrong for top-ranked results","correct":false,"explanation":"The reranker is not always wrong — it is just less needed at the top. Retrieval already did a good job finding the best matches. The reranker's value increases as you go further down the list."},{"text":"It is purely a performance optimization to skip reranking top results","correct":false,"explanation":"Position-aware blending does not skip the reranker for top results. It uses different weight ratios: 75/25 at the top, 60/40 in the middle, 40/60 at the tail. Both signals contribute everywhere."}],"concept":"Position-Aware Blending","difficulty":"hard"}],"partyMembers":[{"name":"Hybrid Search","icon":"server","maxHealth":3},{"name":"Smart Chunking","icon":"data","maxHealth":3},{"name":"Query Expansion","icon":"router","maxHealth":3},{"name":"Position-Aware Blending","icon":"layout","maxHealth":3}],"deathMessages":["Died of zero search results. No index configured.","Lost in the embedding space — no nearest neighbors found.","Drowned in the fusion river. Too many ranked lists to combine.","Starved waiting for the LLM to expand your query