        else if (c === "}") { depth--; if (depth === 0) {
          const jsonStr = html.slice(jsonStart, i + 1);
          try {
            const d = JSON.parse(jsonStr);
            console.log("OK - events:", d.events.length, "stops:", d.stops.length);
