// Change the concept for this specific event
const fixed = html.replace(
  /"title":"Config Storm!","text":(.*?),"concept":"Unified LLM API"/,
  (match, p1) => "\"title\":\"Config Storm!\",\"text\":" + p1 + ",\"concept\":\"Session Persistence\""
);
if (fixed === html) { console.log("NO MATCH"); process.exit(1); }
fs.writeFileSync("pi-mono/index.html", fixed);
console.log("pi-mono: fixed");
'

